class Solution:
    def canSplitArray(self, nums: List[int], m: int) -> bool:
        n = len(nums)
        if n <= 2:
            return True

        prefix_sums = [0] * (n + 1)
        for i in range(n):
            prefix_sums[i+1] = prefix_sums[i] + nums[i]

        dp = [False] * n
        dp[0] = True

        for i in range(1, n):
            for j in range(i):
                subarray_sum = prefix_sums[i+1] - prefix_sums[j+1]
                if dp[j] and (i - j == 1 or subarray_sum >= m):
                    dp[i] = True
                    break

        return dp[n-1]
```

