class Solution:
    def numberOfGoodPartitions(self, nums: List[int]) -> int:
        last_occurrence = {}
        for i, num in enumerate(nums):
            last_occurrence[num] = i

        rightmost = 0
        cuts = 0
        for i, num in enumerate(nums):
            rightmost = max(rightmost, last_occurrence[num])
            if i == rightmost and i != len(nums) - 1:
                cuts += 1

        if cuts == 0:
            return 1

        return pow(2, cuts, 10**9 + 7)
```

