class Solution:
    def longestValidSubstring(self, word: str, forbidden: List[str]) -> int:
        n = len(word)
        max_len = 0
        for i in range(n):
            for j in range(i, n):
                substring = word[i:j+1]
                is_valid = True
                for forbidden_word in forbidden:
                    if forbidden_word in substring:
                        is_valid = False
                        break
                if is_valid:
                    max_len = max(max_len, len(substring))
        return max_len
```

